import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copy characters from userInput to buffer, ensuring no overflow
        int length = Math.min(userInput.length(), bufferSize);
        userInput.getChars(0, length, buffer, 0);

        // Print out the content of the buffer
        for (int i = 0; i < length; i++) {
            System.out.print(buffer[i]);
        }

        scanner.close();
    }
}

